  mom_change = EXCLUDED.mom_change,
  historical_peak = EXCLUDED.historical_peak,
  historical_peak_date = EXCLUDED.historical_peak_date,
  health_status = EXCLUDED.health_status,
  insight = EXCLUDED.insight;
